-- ============================================================================
-- Demo: Global Logistics Shipment Telemetry: Full Type Coverage for ODBC
-- ============================================================================
-- Builds a single Delta table that exercises every Delta Forge data type.
-- Sized for ODBC client workloads (Power BI, Tableau, DBeaver, Excel):
-- 200 rows, 34 columns covering primitives, complex types, and nested complex.
-- ============================================================================

-- ----------------------------------------------------------------------------
-- Zone & Schema
-- ----------------------------------------------------------------------------

CREATE ZONE IF NOT EXISTS {{zone_name}} TYPE EXTERNAL
    COMMENT 'External and Delta tables: demo datasets';

CREATE SCHEMA IF NOT EXISTS {{zone_name}}.bi_demos
    COMMENT 'BI / ODBC reference datasets covering full type matrix';

-- ----------------------------------------------------------------------------
-- Table: shipments_full_types
-- ----------------------------------------------------------------------------
-- Primary fixture for ODBC driver type-mapping. Each column declaration uses
-- a distinct SQL type keyword to ensure the parser, schema observer, and
-- ODBC client all see the right Arrow physical type back.
--
-- Column groups:
--   Integers (INT8/INT16/INT32/INT64): priority_code, warehouse_id,
--                                      route_segment, shipment_id
--   Strings (STRING/VARCHAR/CHAR/TEXT/JSON): tracking_number, carrier_code,
--                                            service_level, container_type,
--                                            currency, event_log_json,
--                                            routing_metadata
--   Floats: weight_kg (FLOAT), distance_km (DOUBLE)
--   Decimals: declared_value DECIMAL(15,4), tax_rate DECIMAL(6,5)
--   Booleans: is_hazardous, requires_signature
--   Dates / times: pickup_date, scheduled_delivery_date (DATE),
--                  daily_cutoff_time (TIME), precise_handoff_time (TIME64),
--                  dispatched_at_utc (TIMESTAMP),
--                  local_handoff_at (TIMESTAMP_NTZ)
--   Binary (BINARY/BYTES/BYTEA): signature_payload, qr_code_bytes,
--                                biometric_blob
--   Arrays: package_dims_cm ARRAY<INT>, waypoint_codes ARRAY<STRING>,
--           sensor_readings ARRAY<DOUBLE>
--   Maps: tags MAP<STRING,STRING>, sla_metrics MAP<STRING,INT>
--   Structs: origin_address, destination_address (flat struct),
--            shipper_contact (struct with nested ARRAY)
-- ----------------------------------------------------------------------------

CREATE DELTA TABLE IF NOT EXISTS {{zone_name}}.bi_demos.shipments_full_types (
    shipment_id              BIGINT,
    priority_code            TINYINT,
    warehouse_id             SMALLINT,
    route_segment            INT,
    tracking_number          STRING,
    carrier_code             VARCHAR(10),
    service_level            CHAR(3),
    container_type           TEXT,
    declared_value           DECIMAL(15,4),
    tax_rate                 DECIMAL(6,5),
    weight_kg                FLOAT,
    distance_km              DOUBLE,
    is_hazardous             BOOLEAN,
    requires_signature       BOOLEAN,
    pickup_date              DATE,
    scheduled_delivery_date  DATE,
    dispatched_at_utc        TIMESTAMP,
    local_handoff_at         TIMESTAMP_NTZ,
    daily_cutoff_time        TIME,
    precise_handoff_time     TIME64,
    signature_payload        BINARY,
    qr_code_bytes            BYTES,
    biometric_blob           BYTEA,
    package_dims_cm          ARRAY<INT>,
    waypoint_codes           ARRAY<STRING>,
    sensor_readings          ARRAY<DOUBLE>,
    tags                     MAP<STRING, STRING>,
    sla_metrics              MAP<STRING, INT>,
    origin_address           STRUCT<line1: STRING, city: STRING, country_code: CHAR(2), postal_code: STRING>,
    destination_address      STRUCT<line1: STRING, city: STRING, country_code: CHAR(2), postal_code: STRING>,
    shipper_contact          STRUCT<name: STRING, phone: STRING, preferred_channels: ARRAY<STRING>>,
    currency                 STRING,
    event_log_json           JSON,
    routing_metadata         JSON
) LOCATION 'delta-odbc-type-coverage/shipments_full_types';

-- ----------------------------------------------------------------------------
-- Seed: 200 shipments with full-spectrum type values
-- ----------------------------------------------------------------------------



-- ----------------------------------------------------------------------------
-- Schema detection
-- ----------------------------------------------------------------------------
-- The creating user is automatically granted ADMIN, so no explicit GRANT is
-- needed.

DETECT SCHEMA FOR TABLE {{zone_name}}.bi_demos.shipments_full_types;

-- ----------------------------------------------------------------------------
-- View: v_shipments_full_types
-- ----------------------------------------------------------------------------
-- Required by ODBC clients that exercise view-backed query paths (e.g. Power
-- BI / Tableau metadata discovery, catalog-routed SELECTs through a view).

CREATE VIEW IF NOT EXISTS {{zone_name}}.bi_demos.v_shipments_full_types AS
SELECT * FROM {{zone_name}}.bi_demos.shipments_full_types;
